#include "pytorch_npu_helper.hpp"

at::Tensor gemm_sigmoid_scaling_residual_add_impl_npu(const at::Tensor& x,
                                                      const at::Tensor& w,
                                                      const at::Tensor& b,
                                                      const at::Tensor& scaling) {
    // Compute GEMM on NPU first (y = x @ w^T + b), then fuse sigmoid*scale + residual in custom kernel.
    at::Tensor y_linear = at::linear(x, w, b);
    at::Tensor result = at::empty_like(y_linear);

    // Extract scaling factor from the scalar tensor as attribute
    const double s = scaling.item<double>();
    EXEC_NPU_CMD(aclnnGemmSigmoidScalingResidualAddCustom, y_linear, w, b, static_cast<float>(s), result);
    return result;
}

